package online.yudream.base.interfaces.platform.wiki.controller;
import jakarta.validation.Valid; import lombok.RequiredArgsConstructor; import online.yudream.base.application.platform.wiki.dto.WikiSearchHitDTO; import online.yudream.base.application.platform.wiki.service.WikiSearchAppService; import online.yudream.base.domain.common.exception.BizException; import online.yudream.base.domain.system.security.service.ApiKeyAuthenticationContext; import online.yudream.base.interfaces.common.Result; import online.yudream.base.interfaces.platform.wiki.request.WikiSearchRequest; import org.springframework.web.bind.annotation.*; import java.util.List;
@RestController @RequestMapping("/api/open/wiki") @RequiredArgsConstructor public class WikiOpenController {private final WikiSearchAppService service;@PostMapping("/{spaceSlug}/search") public Result<List<WikiSearchHitDTO>> search(@PathVariable String spaceSlug,@Valid @RequestBody WikiSearchRequest request){if(!ApiKeyAuthenticationContext.hasPermission("wiki:search:*")&&!ApiKeyAuthenticationContext.hasPermission("wiki:search:"+spaceSlug))throw new BizException("API Key 无知识库检索权限");return Result.ok(service.search(spaceSlug,request.getQuery(),request.getTopK(),request.getPathPrefix(),request.isGraphExpansion()));}}
